onClick:
{{
  bulkUpdateAPI.run(
    // ✅ SUCCESS CALLBACK: Runs when the server says OK
    async () => {
      // 1. Big Success Message
      showAlert("✅ DSR Settled Successfully! Bank and Ledger Entries created.", "success");

      // 2. Refresh the API (Moves the status from 'Pending' to 'Settled')
      await getReportDetails.run(); 

      // 3. 🧹 Clear the Stores (Forces the next report to start fresh)
      await storeValue('stagedChanges', {}); 
      await storeValue('denoms', {}); 

      // 4. Close your modal (Change 'mdlReconciliation' if yours is named differently)
      closeModal('mdlReconciliation'); 
    },

    // ❌ ERROR CALLBACK: Runs if something fails (e.g. database error)
    (err) => {
      showAlert("❌ Settlement Failed: " + (err?.error || "Please check your network"), "error");
    }
  )
}}
